package evaluation

import "sync/atomic"

// MetricsTracker records in-process evaluation throughput counters.
// It is safe for concurrent use by multiple goroutines.
type MetricsTracker struct {
	totalEvaluations int64
	matchCount       int64
	errorCount       int64
}

// NewMetricsTracker constructs a new MetricsTracker with all counters at zero.
func NewMetricsTracker() *MetricsTracker {
	return &MetricsTracker{}
}

// RecordEvaluation increments the total evaluations counter.
func (m *MetricsTracker) RecordEvaluation() {
	atomic.AddInt64(&m.totalEvaluations, 1)
}

// RecordMatch increments the match counter.
func (m *MetricsTracker) RecordMatch() {
	atomic.AddInt64(&m.matchCount, 1)
}

// RecordError increments the error counter.
func (m *MetricsTracker) RecordError() {
	atomic.AddInt64(&m.errorCount, 1)
}

// TotalEvaluations returns the total number of evaluations processed.
func (m *MetricsTracker) TotalEvaluations() int64 {
	return atomic.LoadInt64(&m.totalEvaluations)
}

// MatchCount returns the number of evaluations that resulted in a match.
func (m *MetricsTracker) MatchCount() int64 {
	return atomic.LoadInt64(&m.matchCount)
}

// ErrorCount returns the number of evaluations that failed with an error.
func (m *MetricsTracker) ErrorCount() int64 {
	return atomic.LoadInt64(&m.errorCount)
}

