	assert.Equal(t, int64(0), m.MatchCount())
	assert.Equal(t, int64(0), m.ErrorCount())
}

func TestMetricsTracker_RecordEvaluation(t *testing.T) {
	m := NewMetricsTracker()
	m.RecordEvaluation()
	m.RecordEvaluation()
	m.RecordEvaluation()
	assert.Equal(t, int64(3), m.TotalEvaluations())
	assert.Equal(t, int64(0), m.MatchCount())
	assert.Equal(t, int64(0), m.ErrorCount())
}

func TestMetricsTracker_RecordMatch(t *testing.T) {
	m := NewMetricsTracker()
	m.RecordEvaluation()
	m.RecordEvaluation()
	m.RecordMatch()
	assert.Equal(t, int64(2), m.TotalEvaluations())
	assert.Equal(t, int64(1), m.MatchCount())
	assert.Equal(t, int64(0), m.ErrorCount())
}

func TestMetricsTracker_RecordError(t *testing.T) {
	m := NewMetricsTracker()
	m.RecordEvaluation()
	m.RecordError()
	assert.Equal(t, int64(1), m.TotalEvaluations())
	assert.Equal(t, int64(0), m.MatchCount())
	assert.Equal(t, int64(1), m.ErrorCount())
}

func TestMetricsTracker_ConcurrentAccess(t *testing.T) {
	const goroutines = 100
	const opsPerGoroutine = 50

	m := NewMetricsTracker()
	var wg sync.WaitGroup
	wg.Add(goroutines)

	for i := 0; i < goroutines; i++ {
		go func(id int) {
			defer wg.Done()
			for j := 0; j < opsPerGoroutine; j++ {
				m.RecordEvaluation()
				if j%2 == 0 {
					m.RecordMatch()
				} else {
					m.RecordError()
				}
			}
		}(i)
	}

	wg.Wait()

	total := int64(goroutines * opsPerGoroutine)
	matches := int64(goroutines * (opsPerGoroutine / 2))
	errors := int64(goroutines * (opsPerGoroutine / 2))

	assert.Equal(t, total, m.TotalEvaluations())
	assert.Equal(t, matches, m.MatchCount())
	assert.Equal(t, errors, m.ErrorCount())
}

